<template>
  <select :class="{ 'null-color': selected == 'null' }" name="pricing" id="pricing-select" v-model="selected" @input="handleChange">
    <option :value="null" selected>Pricing</option>
    <option v-for="pricing in pricings" :key="pricing" :value="pricing.key">
      {{ pricing.value }}
    </option>
  </select>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Shared/Option/Pricing";

export default {
  name: "pricing-dropdown",
  props: ["itemPricing"],
  data() {
    return {
      selected: "null",
      pricings: [],
    };
  },
  mounted() {
    axios.get(url).then((result) => (this.pricings = result.data));
  },
  watch: { 
    itemPricing: function(newVal) {
      this.selected = newVal
    }
  },
  methods: {
    handleChange (event) {
      this.$emit("changeSelectValue", event.target.value)
    }
  }
};
</script>
