<template>
  <label :for="id + '-button'" :class="{ active: isActive }" class="toggle-button">
    <!-- <span v-if="isActive" class="toggle-label">{{ enableText }}</span>
    <span v-if="!isActive" class="toggle-label">{{ disabledText }}</span> -->

    <span class="toggle-label">{{ enableText }}</span>

    <input type="checkbox" :disabled="disabled" :id="id + '-button'" v-model="checkedValue" />
    <span class="toggle-switch"></span>
  </label>
</template>

<script>
export default {
  props: {
    disabled: {
      type: Boolean,
      default: false,
    },

    labelEnableText: {
      type: String,
      default: "",
    },

    labelDisableText: {
      type: String,
      default: "",
    },

    id: {
      type: String,
      default: "primary",
    },

    defaultState: {
      type: Boolean,
      default: false,
    },

  },

  data() {
    return {
      currentState: this.defaultState,
    };
  },

  watch: {
    defaultState: function defaultState() {
      this.currentState = Boolean(this.defaultState);
    },
  },

  computed: {
    // currentState() {
    //     return this.defaultState;
    // },

    isActive() {
      return this.currentState;
    },

    enableText() {
      return this.labelEnableText;
    },

    // disabledText() {
    //   return this.labelDisableText;
    // },

    checkedValue: {
      get() {
        return this.currentState;
      },

      set(newValue) {
        this.currentState = newValue;
        this.$emit("changeToggleValue", newValue);
      },
    },
  },
};
</script>

<style scoped>
.toggle-button {
  display:inline-flex;
  vertical-align: middle;
  user-select: none;
  cursor: pointer;
}
.toggle-button span {
  display: inline-block;
  text-align: left;
  width: 155px;
}
label[for="item-active-button"] span {
  width: fit-content;
}
/* label[for="member-vip-discount-button"] span {
  width: fit-content;
} */
.toggle-button input[type="checkbox"] {
  opacity: 0;
  position: absolute;
  width: 1px;
  height: 1px;
}
.toggle-button .toggle-switch {
  display: inline-block;
  height: 22px;
  border-radius: 15px;
  width: 44px;
  /* background: #bfcbd9; */
  box-shadow: inset 0 0 6px #e8e8e8;
  position: relative;
  margin-left: 10px;
  transition: all 0.25s;
}

.toggle-button .toggle-switch::after,
.toggle-button .toggle-switch::before {
  content: "";
  position: absolute;
  display: block;
  height: 18px;
  width: 18px;
  border-radius: 50%;
  left: 1px;
  top: 2px;
  transform: translateX(0);
  transition: all 0.25s cubic-bezier(0.5, -0.6, 0.5, 1.6);
}

.toggle-button .toggle-switch::after {
  background: #fff;
  box-shadow: 0 0 1px #fff;
  border: 1px solid #e8e8e8;
}
.toggle-button .toggle-switch::before {
  background: #4d4d4d;
  box-shadow: 0 0 0 3px rgba(0, 0, 0, 0.1);
  opacity: 0;
}

.active .toggle-switch {
  background: #40b983;
  box-shadow: inset 0 0 1px #40b983;
}

.active .toggle-switch::after,
.active .toggle-switch::before {
  transform: translateX(40px - 18px);
}

.active .toggle-switch::after {
  left: 24px;
  background: #fff;
  box-shadow: 0 0 1px #fff;
}
</style>
