<template>
  <div>
    <table>
      <thead>
        <tr>
          <th class="fixed">Pref</th>
          <th class="fixed">Sec</th>
          <th class="fixed">Last</th>
          <th class="vendor">Vendor</th>
          <th>Vendor Item #</th>
          <th>ITF-14#</th>
          <th>Qty/CS</th>
          <th>Rate/CS</th>
          <th>U.Rate</th>
          <th>V. Rate/CS</th>
          <th>U.Rate</th>
          <th>Order</th>
          <th>Rate Date</th>
        </tr>
      </thead>
      <tbody>
        <tr v-for="purchase in purchases.purchaseList" :key="purchase">
          <td class="fixed round">
            <input type="checkbox" id="purchase-pref" v-model="purchase.pref" />
            <label for="purchase-pref"></label>
          </td>
          <td class="fixed round">
            <input type="checkbox" id="purchase-sec" v-model="purchase.sec" />
            <label for="purchase-sec"></label>
          </td>
          <td class="fixed round">
            <input type="checkbox" id="purchase-last" v-model="purchase.last" />
            <label for="purchase-last"></label>
          </td>
          <td class="vendor">
            <div v-for="vendor in vendors" :key="vendor">
              <div v-if="vendor.vendorNumber == purchase.vendor">
                <input type="text" name="purchase-vendor" :value="purchase.vendor + ' - ' + vendor.name" disabled />
              </div> 
            </div>
          </td>
          <td><input type="text" name="purchase-vendor-item" v-model="purchase.vendorItem" /></td>
          <td><input type="text" name="purchase-itf14" v-model="purchase.itF14" /></td>
          <td><input type="number" name="purchase-cs-qty" v-model="purchase.csQty" /></td>
          <td><input type="number" name="purchase-rate" v-model="purchase.rate" /></td>
          <td><input type="number" name="purchase-unit-rate" v-model="purchase.unitRate" /></td>
          <td><input type="number" name="purchase-vendor-rate" v-model="purchase.vendorRate" disabled /></td>
          <td><input type="number" name="purchase-vendor-unit" v-model="purchase.vendorUnitRate" disabled /></td>
          <td><input type="number" name="purchase-order" v-model="purchase.order" /></td>
          <td><input type="text" name="purchase-rate-date" :value="getFormattedDate(purchase.rateDate)" disabled /></td>
        </tr>
      </tbody>
    </table>
  </div>
</template>

<script>
import axios from "axios";
import moment from "moment";

const url = "http://192.168.168.104:89/Backoffice/Company/Item/";

export default {
  name: "purchase-info",
  data() {
    return {
      ItemProfileId: "",
      purchases: "",
      purchasesVendorId: "",
      vendors: "",
      found: ""
    };
  },
  mounted() {
    if (localStorage.getItem("ItemProfileId")) {
      try {
        this.ItemProfileId = localStorage.getItem("ItemProfileId");
      } catch (e) {
        localStorage.removeItem("ItemProfileId");
      }
    } else {
      this.ItemProfileId = "";
    }

    axios
      .get("http://192.168.168.104:89/Backoffice/Company/Vendor", 
      {
        headers: {
          "x-store": 81,
        },
      })
      .then((response) => {
        this.vendors = response.data;
      });

    axios
      .get(url + "Purchase/" + this.ItemProfileId, 
      {
        params: { PageSize: '20', PageNumber: '1' },
        headers: {
          "x-store": 81,
        },
      })
      .then((response) => {
        this.purchases = response.data;
      });
  },
  methods: {
    getFormattedDate(date) {
      if (date) {
        return moment(date).format("M/DD/YYYY");
      }
    },
    formatPrice(price) {
      if (price) {
        return parseFloat(price).toFixed(2);
      }
    }
  },
};
</script>

<style scoped>
table {
  width: 100%;
  border: 1px solid #e8e8e8;
  border-collapse: collapse;
}
table .fixed {
  width: 30px;
}
table .vendor {
  width: 200px;
}
tbody {
  display: block;
  height: 500px;
  overflow: auto;
}
thead,
tbody tr {
  display: table;
  width: 100%;
  table-layout: fixed;
  white-space: nowrap;
}
thead tr th {
  font-weight: normal;
  position: sticky;
  top: 0;
}
th {
  padding: 10px;
  border-left: 1px solid #e8e8e8;
  border-bottom: 1px solid #e8e8e8;
  text-align: left;
  box-shadow: 0px 0px 0 1px #e8e8e8;
}
table td {
  padding: 10px;
}
tbody tr {
  border-bottom: 1px solid #e8e8e8;
}
tbody tr:hover {
  background: #e6f7ff;
}
input {
  width: fit-content;
  margin-right: 10px;
  padding: 10px;
  border: 1px solid #e8e8e8;
  border-radius: 5px;
}
input[type="number"] {
  width: 45px;
}
.round {
  position: relative;
}
.round label {
  background-color: #fff;
  border: 1px solid #ccc;
  border-radius: 50%;
  cursor: pointer;
  height: 20px;
  left: 15px;
  position: absolute;
  width: 20px;
}
.round label:after {
  border: 2px solid #40b983;
  border-top: none;
  border-right: none;
  content: "";
  height: 3px;
  left: 5px;
  opacity: 0;
  position: absolute;
  top: 7px;
  transform: rotate(-45deg);
  width: 8px;
}
.round input[type="checkbox"] {
  visibility: hidden;
}
.round input[type="checkbox"]:checked + label {
  border-color: #40b983;
}
.round input[type="checkbox"]:checked + label:after {
  opacity: 1;
}
</style>
