<template>
  <select :class="{ 'null-color': selected == 'null' }" name="origin" id="origin-select" v-model="selected" @input="handleChange">
    <option :value="null" disabled selected hidden>Origin</option>
    <option v-for="origin in origins" :key="origin" :value="origin.originID">
      {{ origin.originName }}
    </option>
  </select>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Company/ListAdmin/Origin";

export default {
  name: "origin-dropdown",
  props: ["itemOrigin"],
  data() {
    return {
      selected: "null",
      origins: [],
    };
  },
  methods: {
    handleChange (event) {
      this.$emit("changeSelectValue", event.target.value)
    }
  },
  mounted() {
    axios
      .get(url, {
        headers: {
          "x-store": "81",
        },
      })
      .then((result) => (this.origins = result.data));
  },
  watch: {
    itemOrigin: function (newVal) {
      this.selected = newVal;
    },
  }
};
</script>
