<template>
  <div class="related-wrapper">
    <p class="title">Related UPC</p>
    <div class="label">
      <span>UPC</span>
      <span class="related-print-btn pointer">Print</span>
    </div>
    <div class="related-items-wrapper">
      <div class="related-item-wrapper" v-for="relatedUpc in relatesUpc" :key="relatedUpc">
        <span class="related-item-barcode">{{ relatedUpc.barcode }}</span>
        <span><input type="checkbox" name="related-upc" v-model="relatedUpc.print" /></span>
        <span><button class="delete-related-btn" @click="deleteRelatedUPC(relatedUpc.barcode)"><fa icon="trash"></fa></button></span>
      </div>
    </div>
    <popup>
      <template #header>
        <button class="add-related-btn"><fa icon="add"></fa></button>
      </template>
      <template #content>
        <div class="popup-content">
          <p>Related UPC - Add New</p>
          <input type="text" name="add-upc" placeholder="Enter UPC" v-model="newRelatedUPC">
          <input type="button" class="save-btn" value="Save" v-on:click="addRelatedUPC(newRelatedUPC)" />
        </div>
      </template>
    </popup>
  </div>
</template>

<script>
import popup from "@/components/Popup.vue";
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Company/Item/RelatedUPC/";

export default {
  name: "related-upc",
  components: {
    popup
  },
  data() {
    return {
      relatesUpc: [],
      ItemProfileId: "",
      newRelatedUPC: "",
      interval: null
    };
  },
  mounted() {
    if (localStorage.getItem("ItemProfileId")) {
      try {
        this.ItemProfileId = localStorage.getItem("ItemProfileId");
      } catch (e) {
        localStorage.removeItem("ItemProfileId");
      }
    }

    axios
      .get(url + this.ItemProfileId, {
        headers: {
          "x-store": "81",
        },
      })
      .then((response) => (this.relatesUpc = response.data));
  },
  methods: {
    getRelatedUPC(){
      axios
      .get(url + this.ItemProfileId, {
        headers: {
          "x-store": "81",
        },
      })
      .then((response) => (this.relatesUpc = response.data));
    },
    deleteRelatedUPC(relatedBarcode) {
      axios
        .delete(
          url + this.ItemProfileId + '/' + relatedBarcode,
          {
            headers: {
              "x-store": "81",
            },
          }
        )
        .then((response) => {
          this.saveSuccess = response.data.success;
          this.getRelatedUPC()
        });
    },
    addRelatedUPC(relatedBarcode) {
      axios
        .post(
          url + this.ItemProfileId,
          {
            barcode: relatedBarcode
          },
          {
            headers: {
              "x-store": "81"
            },
          }
        )
        .then((response) => {
          this.saveSuccess = response.data.success;
          this.getRelatedUPC()
        });
    }
  }
};
</script>

<style scoped>
.related-wrapper {
  position: relative;
  height: 100%;
}
.title {
  margin: 0;
  height: 40px;
  color: #11245c;
  font-weight: 700;
}
.label{
  margin-bottom: 10px;
}
.related-print-btn {
  float: right;
}
.related-items-wrapper{
  height: 215px;
  overflow-y: auto;
  position: relative;
}
.related-item-wrapper {
  display: flex;
  justify-content: space-between;
  background-color: #fff;
  margin-bottom: 10px;
  padding: 10px;
  border: 1px solid #e8e8e8;
}
.related-item-barcode {
  width: 50%;
}
.delete-related-btn {
 border: none;
 background-color: #fff;
}
.add-related-btn {
  position: absolute;
  bottom: 0;
  right: 0;
  background-color: #fff;
  padding: 10px 12px;
  border: 1px solid #e8e8e8;
  border-radius: 25px;
  color: #777777;
}
.popup-content {
  z-index: 1;
  position: absolute;
  background: #fff;
  border: 1px solid #e8e8e8;
  box-shadow: 0 4px 8px 0 rgba(0, 0, 0, 0.10), 0 6px 20px 0 rgba(0, 0, 0, 0.10);
  border-radius: 10px;
  padding: 20px;
}
input {
  margin-right: 10px;
  padding: 10px;
  border: 1px solid #e8e8e8;
  border-radius: 5px;
}
.save-btn {
  margin-top: 10px;
  border: none;
  background: #40b983;
  font-size: 16px;
  color: #fff;
  padding: 10px 60px;
  border-radius: 5px;
}
</style>
