<template>
  <select :class="{ 'null-color': selected == 'null' }" name="brand" id="brand-select" v-model="selected" @input="handleChange">
    <option :value="null" disabled selected hidden>Brand</option>
    <option v-for="brand in brands" :key="brand" :value="brand.brandID">
      {{ brand.brandName }}
    </option>
  </select>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Company/ListAdmin/Brand";

export default {
  name: "brand-dropdown",
  props: ["itemBrand"],
  data() {
    return {
      selected: "null",
      brands: [],
    };
  },
  mounted() {
    axios
      .get(url, {
        headers: {
          "x-store": "81",
        },
      })
      .then((result) => (this.brands = result.data));
  },
  watch: {
    itemBrand: function (newVal) {
      this.selected = newVal;
    },
  },
  methods: {
    handleChange (event) {
      this.$emit("changeSelectValue", event.target.value)
    }
  }
};
</script>
