<template>
  <select :class="{ 'null-color': selected == 'null' }" name="retail-type" id="retail-select" v-model="selected" @input="handleChange">
    <option :value="null" selected>Retail Type</option>
    <option v-for="retail in retails" :key="retail" :value="retail.key">
      {{ retail.value }}
    </option>
  </select>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Shared/Option/RetailType";

export default {
  name: "retail-type-dropdown",
  props: ["itemRetailType"],
  data() {
    return {
      selected: "null",
      retails: [],
    };
  },
  mounted() {
    axios.get(url).then((result) => (this.retails = result.data));
  },
  watch: { 
    itemRetailType: function(newVal) {
      this.selected = newVal
    }
  },
  methods: {
    handleChange (event) {
      this.$emit("changeSelectValue", event.target.value)
    }
  }
};
</script>
