<template>
  <select :class="{ 'null-color': selected == 'null' }" name="category" id="category-select" v-model="selected" @input="handleChange">
    <option :value="null" disabled selected hidden>Category</option>
    <option v-for="category in categories" :key="category" :value="category.categoryNo">
      {{ category.name }}
    </option>
  </select>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Company/Category/Category";

export default {
  name: "category-dropdown",
  props: ["itemCategroy"],
  data() {
    return {
      selected: "null",
      categories: [],
    };
  },
  mounted() {
    axios
      .get(url, {
        headers: {
          "x-store": "81",
        },
      })
      .then((result) => (this.categories = result.data));
  },
  watch: {
    itemCategroy: function (newVal) {
      this.selected = newVal;
    },
  },
  methods: {
    handleChange (event) {
      this.$emit("changeSelectValue", event.target.value)
    }
  }
};
</script>
