<template>
  <select :class="{ 'null-color': selected == 'null' }" name="quantity-pricing" id="quantity-pricing-select" v-model="selected" @input="handleChange">
    <option :value="null" selected></option>
    <option v-for="quantityPricing in quantityPricings" :key="quantityPricing" :value="quantityPricing.key">
      {{ quantityPricing.value }}
    </option>
  </select>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Shared/Option/QuantityPricePricing";

export default {
  name: "quantity-pricing-dropdown",
  props: ["itemQuantityPricing"],
  data() {
    return {
      selected: "null",
      quantityPricings: [],
    };
  },
  mounted() {
    axios.get(url).then((result) => (this.quantityPricings = result.data));
  },
  watch: {
    itemQuantityPricing: function (newVal) {
      this.selected = newVal;
    },
  },
  methods: {
    handleChange (event) {
      this.$emit("changeSelectValue", event.target.value)
    }
  }
};
</script>
