      itemQuantityPrice: {},
      itemDiscountNeverExpired: "",
      itemQuantityPriceNeverExpired: "",
      discountNeverExpired: "",
      itemStoreCoupon: {},
      itemSale: {},
      itemPurchase: {},
      itemMixMatch: {},
      pageSize: 20,
      pageNumber: 1,
    };
  },
  created() {
    this.storeCode = 81;
  },
  mounted() {
    axios
      .get("/shared/Filter/Item")
      .then((response) => {
        var list = [];
      
        response.data.map(function(value) {
          switch (value.key) {
            case 'Barcode':
              list.push({title:value.key, type:value.dataType, options:value.options, value: '', checked: true})
              break;
            case 'NameDescription':
              list.push({title:value.key, type:value.dataType, options:value.options, value: '', checked: true})
              break;
            case 'Department':
              list.push({title:value.key, type:value.dataType, options:value.options, value: '', checked: true})
              break;
            case 'RetailType':
              list.push({title:value.key, type:value.dataType, options:value.options, value: '', checked: true})
              break;
            case 'PriceType':
              list.push({title:value.key, type:value.dataType, options:value.options, value: '', checked: true})
              break;
            default:
              list.push({title:value.key, type:value.dataType, options:value.options, value: '', checked: false})
              break;
          }
        });

        this.filters = list;

        for (let i = 0; i < this.filters.length; i++) {
          if (this.filters[i]['checked'] == true) {
            this.selectedFilters.push(this.filters[i]);
          }
        }
      });

    if (localStorage.getItem("ItemProfileId")) {
      try {
        this.ItemProfileId = localStorage.getItem("ItemProfileId");
      } catch (e) {
        localStorage.removeItem("ItemProfileId");
      }
    }

    this.getItemInfo();

  },
  methods: {
    getItemInfo() {
      axios
        .get(url + "Detail/" + this.ItemProfileId, {
          headers: {
            "x-store": this.storeCode,
          },
        })
        .then((response) => {
          this.itemData = response.data;
          this.itemPrice = parseFloat(response.data.price).toFixed(2);
          this.itemDepartment = response.data.department;
        });

      axios
        .get(url + "Discount/" + this.ItemProfileId, {
          headers: {
            "x-store": this.storeCode,
          },
        })
        .then((response) => {
          this.itemDiscount = response.data;
          this.itemDiscountNeverExpired = response.data.neverExpired;
        });

      axios
        .get(url + "StoreCoupon/" + this.ItemProfileId, {
          headers: {
            "x-store": this.storeCode,
          },
        })
        .then((response) => {
          this.itemStoreCoupon = response.data;
        });

      axios
        .get(url + "QuantityPrice/" + this.ItemProfileId, {
          headers: {
            "x-store": this.storeCode,
          },
        })
        .then((response) => {
          this.itemQuantityPrice = response.data;
          this.itemMixMatch = response.data.mixMatch;
          this.itemQuantityPriceNeverExpired = response.data.neverExpired;
        });

      if (this.itemQuantityPriceNeverExpired == true || this.itemDiscountNeverExpired == true) {
        this.discountNeverExpired = true;
      }

      axios
        .get(url + "Sale/" + this.ItemProfileId, {
          headers: {
            "x-store": this.storeCode,
          },
        })
        .then((response) => {
          this.itemSale = response.data;
        });

      axios
        .get(url + "Purchase/" + this.ItemProfileId, 
        {
          params: { PageSize: '20', PageNumber: '1' },
          headers: {
            "x-store": this.storeCode,
          },
        })
        .then((response) => {
          this.itemPurchase = response.data;
        });
    },
    insertSpaces(text) {
      text = text.replace(/([a-z])([A-Z])/g, '$1 $2');
      text = text.replace(/([A-Z])([A-Z][a-z])/g, '$1 $2');
      return text;
    },
    kebabCase(text) {
      text = text.replace(/([a-z])([A-Z])/g, "$1-$2");
      text = text.replace(/[\s_]+/g, '-').toLowerCase();
      return text;
    },
    camelize(text) {
      return text.replace(/(?:^\w|[A-Z]|\b\w)/g, function(word, index) {
        return index === 0 ? word.toLowerCase() : word.toUpperCase();
      }).replace(/\s+/g, '');
    },
    formatDateTime(date) {
      return moment(date).format("MMM D, YYYY h:mm:ss");
    },
    formatDate(date) {
      if (date) {
        return moment(date).format("YYYY-MM-DD");
      }
    },
    formatPrice(price) {
      if (price) {
        return parseFloat(price).toFixed(2);
      }
    },
    submitStoreCode() {},
    closeFilterList() {
      this.active = false;
    },
    checkedFilter(filter) {
      if (filter['checked'] == true) {
        this.selectedFilters.push(filter)
      } else {
        for (var i = this.selectedFilters.length - 1; i >= 0; --i) {
          if (this.selectedFilters[i].title == filter['title']) {
            this.selectedFilters.splice(i,1);
          }
        }
        // this.selectedFilters.splice(this.selectedFilters.indexOf(filter), 1);
      }  
    },
    submitFilters() {
      if (localStorage.getItem('filterSearch')) {
        for (let i = 0; i < this.selectedFilters.length; i++) {
          
          this.filterValue += this.selectedFilters[i]['value']
        }
        if (this.filterValue.length == 0) {
            localStorage.removeItem('filterSearch');
        } else {
          this.saveFilters();
        }
      } else {
        this.saveFilters();
      }
      this.$router.go(-1);
    },
    saveFilters() {
      const parsed = JSON.stringify(this.selectedFilters);
      localStorage.setItem('filterSearch', parsed);
    },
    saveItemInfo(itemBarcode) {
      axios
        .put(
          url + "Detail/" + itemBarcode,
          {
            itemName: this.itemData.itemName,
            description: this.itemData.description,
            qty: this.itemData.qty,
            price: this.itemPrice,
            hotKey: this.itemData.hotKey,
            active: this.itemData.active,
            department: this.itemData.department,
            category: this.itemData.category,
            itemType: this.itemData.itemType,
            priceType: this.itemData.priceType,
            retailType: this.itemData.retailType,
            brandID: this.itemData.brandID,
            vendorCode: this.itemData.vendorCode,
            handleBy: this.itemData.handleBy,
            origin: this.itemData.origin,
            baseCount: this.itemData.baseCount,
            wt: this.itemData.wt,
            packing: this.itemData.packing,
            measureCount: this.itemData.measureCount,
            measureUnit: this.itemData.measureUnit,
            calculationCount: this.itemData.calculationCount,
            calculationUnit: this.itemData.calculationUnit,
            taxable: this.itemData.taxable,
            taxGroup: this.itemData.taxGroup,
            redemption: this.itemData.redemption,
            sbt: this.itemData.sbt,
            foodstamp: this.itemData.foodstamp,
            cvv: this.itemData.cvv,
            wic: this.itemData.wic,
            wicPrice: this.itemData.wicPrice,
            location: this.itemData.location,
            limit: this.itemData.limit,
            tare: this.itemData.tare,
            legalAge: this.itemData.legalAge,
            goodForDayCount: this.itemData.goodForDayCount,
            miscType: this.itemData.miscType,
            onlinePay: this.itemData.onlinePay,
            loyalty: this.itemData.loyalty,
            vipDiscount: this.itemData.vipDiscount,
            memberVIPDiscount: this.itemData.memberVIPDiscount,
            reward: this.itemData.reward,
            serviceNeeded: this.itemData.serviceNeeded,
            finalSale: this.itemData.finalSale
          },
          {
            headers: {
              "x-store": this.storeCode,
              "x-timestamp": localISOTime,
            },
          }
        )
        .then((response) => {
          this.saveSuccess = response.data.success;

          setTimeout(() => (this.saveSuccess = false), 2500);
        });
    },
    addItem() {
      this.$router.push({ name: "new-item" });
    },
    deleteItem(itemBarcode) {
      axios
        .delete(url + itemBarcode, {
          headers: {
            "x-store": this.storeCode,
          },
        })
        .then((response) => {
          this.deleteSuccess = response.data.success;

          setTimeout(() => (this.deleteSuccess = false), 2500);
        });
    },
  },
};
</script>

