<template>
  <select :class="{ 'null-color': selected == 'null' }" name="department" id="department-select" v-model="selected" @input="handleChange">
    <option :value="null" selected>Department</option>
    <option v-for="department in departments" :key="department" :value="department.departmentNo">
      {{ department.displayName }}
    </option>
  </select>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Company/ListAdmin/Department";

export default {
  name: "department-dropdown",
  props: ["itemDepartment"],
  data() {
    return {
      selected: "null",
      departments: []
    };
  },
  mounted() {
    axios
      .get(url, {
        headers: {
          "x-store": "81",
        },
      })
      .then((result) => (this.departments = result.data));
  },
  watch: { 
    itemDepartment: function(newValue) {
      this.selected = newValue
    }
  },
  methods: {
    handleChange (event) {
      this.$emit("changeSelectValue", event.target.value)
    }
  }
};
</script>
