<template>
  <div>
    <p class="title">Memo</p>
    <textarea name="item-memo" v-model="itemMemo"></textarea>
    <div v-if="status === 200">
      <input type="button" class="save-btn change-memo" value="Save" @click="changeMemo(ItemProfileId)" />
    </div>
    <div v-else>
      <input type="button" class="save-btn add-memo" value="Save" @click="addMemo(ItemProfileId)" />
    </div>
  </div>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Company/Item/ItemMemo/";

var tzoffset = (new Date()).getTimezoneOffset() * 60000; //offset in milliseconds
var localISOTime = (new Date(Date.now() - tzoffset)).toISOString();

export default {
  name: "item-memo",
  data() {
    return {
      itemMemo: null,
      ItemProfileId: "",
      status:""
    };
  },
  mounted() {
    if (localStorage.getItem("ItemProfileId")) {
      try {
        this.ItemProfileId = localStorage.getItem("ItemProfileId");
      } catch (e) {
        localStorage.removeItem("ItemProfileId");
      }
    }

    axios
      .get(url + this.ItemProfileId, {
        headers: {
          "x-store": "81",
        },
      })
      .then((response) => {
        this.itemMemo = response.data.memo;
        this.status = response.status;
      });
  },
  methods: {
    changeMemo(ItemProfileId) {
      axios
        .put(
          url + ItemProfileId,
          {
            memo: this.itemMemo
          },
          {
            headers: {
              "x-store": "81",
              "x-timestamp": localISOTime,
            },
          }
        )
        .then((response) => {
          this.saveSuccess = response.data.success;
        });
    },
    addMemo(ItemProfileId) {
      axios
        .post(
          url + ItemProfileId,
          {
            memo: this.itemMemo
          },
          {
            headers: {
              "x-store": "81",
            },
          }
        )
        .then((response) => {
          this.saveSuccess = response.data.success;
        });
    }
  }
};
</script>

<style scoped>
textarea {
  width: 400px;
  height: 300px;
  padding: 10px;
  border: 1px solid #e8e8e8;
  border-radius: 5px;
  resize: none;
}
.save-btn {
  margin-top: 10px;
  border: none;
  background: #40b983;
  font-size: 16px;
  color: #fff;
  padding: 10px 60px;
  border-radius: 5px;
}
</style>
