<template>
  <select :class="{ 'null-color': selected == 'null' }" name="employee" id="employee-select" v-model="selected" @input="handleChange">
    <option :value="null" disabled selected hidden>Handle By</option>
    <option v-for="employee in employees" :key="employee" :value="employee.employeeNumber">
      {{ employee.firstName }} {{ employee.lastName }}
    </option>
  </select>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Company/Employee";

export default {
  name: "employee-dropdown",
  props: ["itemHandleBy"],
  data() {
    return {
      selected: "null",
      employees: [],
    };
  },
  mounted() {
    axios
      .get(url, {
        headers: {
          "x-store": "81",
        },
      })
      .then((result) => (this.employees = result.data));
  },
  watch: {
    itemHandleBy: function (newVal) {
      this.selected = newVal;
    },
  },
  methods: {
    handleChange (event) {
      this.$emit("changeSelectValue", event.target.value)
    }
  }
};
</script>
