<template>
  <select :class="{ 'null-color': selected == 'null' }" name="vendor" id="vendor-select" v-model="selected" @input="handleChange">
    <option :value="null" disabled selected hidden>Pr. Vendor</option>
    <option v-for="vendor in vendors" :key="vendor" :value="vendor.vendorNumber">
      {{ vendor.vendorNumber }} - {{ vendor.name }}
    </option>
  </select>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Company/Vendor";

export default {
  name: "vendor-dropdown",
  props: ["itemVendor"],
  data() {
    return {
      selected: "null",
      vendors: [],
    };
  },
  mounted() {
    axios
      .get(url, {
        headers: {
          "x-store": "81",
        },
      })
      .then((result) => (this.vendors = result.data));
  },
  watch: {
    itemVendor: function (newVal) {
      this.selected = newVal;
    },
  },
  methods: {
    handleChange (event) {
      this.$emit("changeSelectValue", event.target.value)
    }
  }
};
</script>
