<template>
  <div>
    <p class="title">Price History</p>
    <table>
      <thead>
        <tr>
          <th>Update Date & Time</th>
          <th>Price($)</th>
        </tr>
      </thead>
      <tbody>
        <tr v-for="histroy in histories" :key="histroy">
          <td>{{ getFormattedDate(histroy.updatedDatetime) }}</td>
          <td>{{ formatPrice(histroy.price) }}</td>
        </tr>
      </tbody>
    </table>
  </div>
</template>

<script>
import axios from "axios";
import moment from "moment";

const url = "http://192.168.168.104:89/Backoffice/Company/Item/PriceHistory/";

export default {
  name: "price-history",
  data() {
    return {
      histories: "",
      ItemProfileId: "",
    };
  },
  mounted() {
    if (localStorage.getItem("ItemProfileId")) {
      try {
        this.ItemProfileId = localStorage.getItem("ItemProfileId");
      } catch (e) {
        localStorage.removeItem("ItemProfileId");
      }
    }

    axios
      .get(url + this.ItemProfileId, {
        headers: {
          "x-store": "81",
        },
      })
      .then((response) => (this.histories = response.data));
  },
  methods: {
    getFormattedDate(date) {
      return moment(date).format("MMM D, YYYY h:mm:ss");
    },
    formatPrice(price) {
      if (price) {
        return parseFloat(price).toFixed(2);
      }
    }
  },

};
</script>

<style scoped>
table {
  width: 400px;
  border: 1px solid #e8e8e8;
  border-collapse: collapse;
}
tbody {
  display: block;
  height: 500px;
  overflow: auto;
}
thead, tbody tr {
    display: table;
    width: 100%;
    table-layout: fixed;/* even columns width , fix width of table too*/
}
thead {
    width: calc( 100% - 1em )/* scrollbar is average 1em/16px width, remove it from thead width */
}

/* Set header to stick to the top of the container. */
thead tr th {
  position: sticky;
  top: 0;
}

th {
  padding: 16px;
  padding-left: 15px;
  border-left: 1px solid #e8e8e8;
  border-bottom: 1px solid #e8e8e8;
  text-align: left;
  box-shadow: 0px 0px 0 1px #e8e8e8;
}
table td {
  padding: 16px;
}
tbody tr {
  border-bottom: 1px solid #e8e8e8;
}
tbody tr:hover {
  background: #e6f7ff;
}
</style>
