<template>
  <select :class="{ 'null-color': selected == 'null' }" name="type" id="type-select" v-model="selected" @input="handleChange">
    <option :value="null" disabled selected hidden>Type</option>
    <option v-for="type in types" :key="type" :value="type.key">
      {{ type.value }}
    </option>
  </select>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Shared/Option/Type";

export default {
  name: "type-dropdown",
  props: ["itemType"],
  data() {
    return {
      selected: "null",
      types: [],
    };
  },
  mounted() {
    axios
      .get(url, {
        headers: {
          "x-store": "81",
        },
      })
      .then((result) => (this.types = result.data));
  },
  watch: {
    itemType: function (newVal) {
      this.selected = newVal;
    },
  },
  methods: {
    handleChange (event) {
      this.$emit("changeSelectValue", event.target.value)
    }
  }
};
</script>
