<template>
  <div>
    <img :src="imgURL" @click="$refs.file.click()" />
    <input type="file" ref="file" style="display: none" @change="uploadImage" name="image" id="image"  accept="image/*" >
  </div>
</template>

<script>
/* eslint-disable */
import axios from "axios";
import defaultImage from "@/assets/img/default.png"

const url = "http://192.168.168.104:89/Backoffice/Company/Item/Picture/";

export default {
  name: "item-image",
  data() {
    return {
      image: "",
      ItemProfileId: "",
      defaultImage: defaultImage,
      renderKey: 0
    };
  },
  mounted() {
    if (localStorage.getItem("ItemProfileId")) {
      try {
        this.ItemProfileId = localStorage.getItem("ItemProfileId");
      } catch (e) {
        localStorage.removeItem("ItemProfileId");
      }
    }

    axios
      .get(url + this.ItemProfileId, {
        headers: {
          "x-store": "81",
        },
      })
      .then(response => (this.image = response.data))
      .catch(error => console.log(error.response))
  },
  computed: {
    imgURL() {
      if (this.image) {
        return "data:image/jpeg;base64," + this.image;
      } else {
        return defaultImage;
      }
    },
  },
  methods: {
    uploadImage(e) {
      let imageData = new FormData()
    
      imageData.append('name', 'image')
      imageData.append('file', e.target.files[0])

      axios.post(url + this.ItemProfileId, imageData, {
        headers: {
          "x-store": "81",
        },
      })
      .then(response => (this.image = response.data))
      .catch(error => console.log(error.response))
    }
  }
};
</script>

<style scoped>
img {
  width: 100%;
  border: 1px solid #e8e8e8;
}
</style>
