<template>
  <select :class="{ 'null-color': selected == 'null' }" name="redemption" id="redemption-select" v-model="selected" @input="handleChange">
    <option :value="null" disabled selected hidden></option>
    <option v-for="redemption in redemptions" :key="redemption" :value="redemption.itemNo">
      {{ redemption.name }}
    </option>
  </select>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Company/DepositRedemption/Item";

export default {
  name: "redemption-dropdown",
  props: ["itemRedemption"],
  data() {
    return {
      selected: "null",
      redemptions: [],
    };
  },
  mounted() {
    axios
      .get(url, {
        headers: {
          "x-store": "81",
        },
      })
      .then((result) => (this.redemptions = result.data));
  },
  watch: {
    itemRedemption: function (newVal) {
      this.selected = newVal;
    },
  },
  methods: {
    handleChange (event) {
      this.$emit("changeSelectValue", event.target.value)
    }
  }
};
</script>
