<template>
  <select :class="{ 'null-color': selected == 'null' }" name="group" id="group-select" v-model="selected" @input="handleChange">
    <option :value="null" disabled selected hidden></option>
    <option v-for="group in groups" :key="group" :value="group.taxGroupID">
      {{ group.taxGroupID }} - {{ group.taxGroupName }}
    </option>
  </select>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Company/ListAdmin/TaxGroup";

export default {
  name: "tax-group-dropdown",
  props: ["itemTaxGroup"],
  data() {
    return {
      selected: "null",
      groups: [],
    };
  },
  mounted() {
    axios
      .get(url, {
        headers: {
          "x-store": "81",
        },
      })
      .then((result) => (this.groups = result.data));
  },
  watch: {
    itemTaxGroup: function (newVal) {
      this.selected = newVal;
    },
  },
  methods: {
    handleChange (event) {
      this.$emit("changeSelectValue", event.target.value)
    }
  }
};
</script>
