<template>
  <div class="tabs-wrapper">
    <ul class="tabs">
      <li
        class="tab pointer"
        :class="{ 'white-bg': tab.hash !== activeTabHash, 'green-bg': tab.hash === activeTabHash }"
        v-for="tab in tabs"
        :key="tab.title"
        @click="activeTabHash = tab.hash"
      >
        {{ tab.title }}
      </li>
    </ul>
    <slot />
  </div>
</template>

<script setup>
import { ref, provide } from "vue";

const activeTabHash = ref("");
const tabs = ref([]);

provide("addTab", (tab) => {
  const count = tabs.value.push(tab);

  if (count === 1) {
    activeTabHash.value = tab.hash;
  }
});
provide("activeTabHash", activeTabHash);


</script>

<style scoped>
.tabs-wrapper{
    width: 100%;
}
.tabs {
  display: flex;
  border: 1px solid #e8e8e8;
  border-radius: 25px;
  padding: 0;
  margin: 0;
  width: fit-content;
  margin-bottom: 20px;
}
.tab {
  padding: 10px 30px;
}
.tab:first-child {
  border-top-left-radius: 25px;
  border-bottom-left-radius: 25px;
}
.tab:last-child {
  border-top-right-radius: 25px;
  border-bottom-right-radius: 25px;
}
.green-bg{
  background: #40b983;
  color: #ffffff;
}
.white-bg{
  background: #ffffff;
  color: #000000;
}
</style>
