<template>
  <select :class="{ 'null-color': selected == 'null' }" name="location" id="location-select" v-model="selected" @input="handleChange">
    <option :value="null" disabled selected hidden></option>
    <option v-for="location in locations" :key="location" :value="location.locationCode">
      {{ location.locationCode }} - {{ location.locationName }}
    </option>
  </select>
</template>

<script>
import axios from "axios";

const url = "http://192.168.168.104:89/Backoffice/Company/LocationSetup";

export default {
  name: "location-dropdown",
  props: ["itemLocation"],
  data() {
    return {
      selected: "null",
      locations: [],
    };
  },
  mounted() {
    axios
      .get(url, {
        headers: {
          "x-store": "81",
        },
      })
      .then((result) => (this.locations = result.data));
  },
  watch: {
    itemLocation: function (newVal) {
      this.selected = newVal;
    },
  },
  methods: {
    handleChange (event) {
      this.$emit("changeSelectValue", event.target.value)
    }
  }
};
</script>
